interface StreamPlatformSelectorProps {
  selectedPlatforms: string[];
  onPlatformToggle: (platformId: string) => void;
  className?: string;
}

const StreamPlatformSelector: React.FC<StreamPlatformSelectorProps> = ({
  selectedPlatforms,
  onPlatformToggle,
  className,
}) => {
  const getPlatformsByCategory = (category: StreamingPlatform['category']) => {
    return STREAMING_PLATFORMS.filter(p => p.category === category);
  };

  const PlatformIcon = ({ platform }: { platform: StreamingPlatform }) => {
    const IconComponent = PlatformIcons[platform.icon];
    if (IconComponent) {
      return <IconComponent className="w-10 h-10" />;
    }
    return (
      <div className="w-10 h-10 rounded-full bg-muted flex items-center justify-center text-base font-bold">
        {platform.name.charAt(0)}
      </div>
    );
  };

  return (
    <div className={cn("space-y-6", className)}>
      {PLATFORM_CATEGORIES.map((category) => {
        const platforms = getPlatformsByCategory(category.id as StreamingPlatform['category']);

        return (
          <div key={category.id} className="space-y-3">
            <h4 className="text-base font-semibold text-muted-foreground uppercase tracking-wider">
              {category.name}
            </h4>
            <ScrollArea className="w-full whitespace-nowrap">
              <div className="flex gap-4 pb-4" style={{ minHeight: '220px' }}>
                <div className="grid grid-rows-2 grid-flow-col gap-4">
                  {platforms.map((platform) => {
                    const isSelected = selectedPlatforms.includes(platform.id);

                    return (
                      <button
                        key={platform.id}
                        onClick={() => onPlatformToggle(platform.id)}
                        className={cn(
                          "relative flex flex-col items-center justify-center gap-3 p-5 rounded-2xl border-2 transition-all duration-200 min-w-[140px] w-[140px] h-[100px]",
                          "hover:scale-105 hover:shadow-lg",
                          isSelected
                            ? "border-primary bg-primary/10 shadow-md"
                            : "border-border bg-card hover:border-primary/50"
                        )}
                        style={{
                          '--platform-color': platform.color,
                        } as React.CSSProperties}
                      >
                        {isSelected && (
                          <div className="absolute top-2 right-2 w-6 h-6 bg-primary rounded-full flex items-center justify-center">
                            <Check className="w-4 h-4 text-primary-foreground" />
                          </div>
                        )}
                        <div
                          className="transition-colors"
                          style={{ color: isSelected ? platform.color : 'currentColor' }}
                        >
                          <PlatformIcon platform={platform} />
                        </div>
                        <span className={cn(
                          "text-base font-semibold text-center whitespace-normal leading-tight",
                          isSelected ? "text-foreground" : "text-muted-foreground"
                        )}>
                          {platform.name}
                        </span>
                        {platform.comingSoon && (
                          <span className="absolute bottom-2 text-xs text-muted-foreground">
                            Coming Soon
                          </span>
                        )}
                      </button>
                    );
                  })}
                </div>
              </div>
              <ScrollBar orientation="horizontal" />
            </ScrollArea>
          </div>
        );
      })}
    </div>
  );
};

export default StreamPlatformSelector;
